'use client'
// sjaj.hr v9 - secure session auth with httpOnly cookies
import { useState, useEffect, useMemo, useCallback } from 'react'

const t = {
  bg: '#050505', bgCard: '#0a0a0a', card: '#111111', border: '#1f1f1f', borderLight: '#262626',
  text: '#ffffff', textMuted: '#a3a3a3', textDim: '#737373', accent: '#10b981', accentGlow: 'rgba(16,185,129,0.15)', urgent: '#ef4444'
}
const cardStyle = { background: t.card, border: `1px solid ${t.border}`, borderRadius: 16 }
const btnPrimary = { padding: '14px 28px', background: t.accent, border: 'none', borderRadius: 10, color: '#000', fontWeight: 700, fontSize: 15, cursor: 'pointer' }
const btnSecondary = { padding: '14px 28px', background: 'transparent', border: `1px solid ${t.borderLight}`, borderRadius: 10, color: t.text, fontWeight: 600, fontSize: 15, cursor: 'pointer' }
const inputStyle = { width: '100%', padding: '14px 16px', background: t.bgCard, border: `1px solid ${t.border}`, borderRadius: 10, color: t.text, fontSize: 15, outline: 'none', boxSizing: 'border-box' as const }
const selectStyle = { ...inputStyle, cursor: 'pointer' }

const CROATIAN_CITIES = [
  'Zagreb', 'Split', 'Rijeka', 'Osijek', 'Zadar', 'Slavonski Brod', 'Pula', 'Sesvete', 'Karlovac',
  'Varaždin', 'Šibenik', 'Sisak', 'Vinkovci', 'Velika Gorica', 'Vukovar', 'Bjelovar',
  'Dubrovnik', 'Koprivnica', 'Požega', 'Čakovec', 'Petrinja', 'Gospić', 'Virovitica',
  'Kutina', 'Samobor', 'Solin', 'Đakovo', 'Knin', 'Makarska', 'Metković'
]

type User = { id: number; email: string; role: 'client' | 'cleaner'; city?: string }
type Job = { id: number; title: string; location: string; price: number; status: string; created_at: string; property_type?: string; is_urgent?: boolean; description?: string; cleaner_id?: number; cleaner_name?: string; application_count?: number; city?: string }
type Application = { id: number; job_id: number; cleaner_id: number; status: string; message?: string; created_at: string; cleaner_name?: string; rating?: number; phone?: string; email?: string; title?: string; location?: string; price?: number; job_status?: string }
type Stats = { totalJobs?: number; activeApplications?: number; totalSpent?: number; completedJobs?: number; pendingApplications?: number; totalEarned?: number; rating?: number }

export default function Home() {
  const [mounted, setMounted] = useState(false)
  const [view, setView] = useState<'landing' | 'auth' | 'dashboard'>('landing')
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login')
  const [userRole, setUserRole] = useState<'client' | 'cleaner' | null>(null)
  const [userName, setUserName] = useState('')
  const [userId, setUserId] = useState('')
  const [isOffline, setIsOffline] = useState(false)

  // Check authentication via httpOnly session cookie
  useEffect(() => {
    const checkAuth = async () => {
      try {
        const res = await fetch('/api/auth/me')
        const data = await res.json()
        if (data.user) {
          setUserRole(data.user.role)
          setUserName(data.user.email)
          setUserId(data.user.id.toString())
          setView('dashboard')
        }
      } catch {
        // Not authenticated or network error
      }
      setMounted(true)
    }
    checkAuth()
  }, [])

  // Offline detection
  useEffect(() => {
    const handleOnline = () => setIsOffline(false)
    const handleOffline = () => setIsOffline(true)
    
    setIsOffline(!navigator.onLine)
    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)
    
    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('offline', handleOffline)
    }
  }, [])

  const login = (u: User) => {
    // Session cookie is set by the API - just update local state
    setUserRole(u.role); setUserName(u.email); setUserId(u.id.toString()); setView('dashboard')
  }

  const logout = async () => {
    try {
      await fetch('/api/auth/logout', { method: 'POST' })
    } catch {
      // Continue with logout even if API fails
    }
    setUserRole(null); setUserName(''); setUserId(''); setView('landing')
  }

  // Offline banner component
  const OfflineBanner = () => isOffline ? (
    <div style={{ 
      position: 'fixed', 
      top: 0, 
      left: 0, 
      right: 0, 
      background: '#dc2626', 
      color: '#fff', 
      padding: '12px 24px', 
      textAlign: 'center', 
      fontWeight: 600, 
      fontSize: 14, 
      zIndex: 9999,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: 8
    }}>
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
        <line x1="1" y1="1" x2="23" y2="23"/><path d="M16.72 11.06A10.94 10.94 0 0 1 19 12.55"/><path d="M5 12.55a10.94 10.94 0 0 1 5.17-2.39"/><path d="M10.71 5.05A16 16 0 0 1 22.58 9"/><path d="M1.42 9a15.91 15.91 0 0 1 4.7-2.88"/><path d="M8.53 16.11a6 6 0 0 1 6.95 0"/><line x1="12" y1="20" x2="12.01" y2="20"/>
      </svg>
      Nema internetske veze — neke funkcije mozda nece raditi
    </div>
  ) : null

  if (!mounted) return <div style={{ minHeight: '100vh', background: t.bg, display: 'flex', alignItems: 'center', justifyContent: 'center' }}><div style={{ color: t.accent, fontSize: 20, fontWeight: 600 }}>Učitavanje...</div></div>
  if (view === 'landing') return <><OfflineBanner /><LandingPage onLogin={() => { setAuthMode('login'); setView('auth') }} onRegister={() => { setAuthMode('register'); setView('auth') }} /></>
  if (view === 'auth') return <><OfflineBanner /><AuthPage mode={authMode} setMode={setAuthMode} onLogin={login} onBack={() => setView('landing')} /></>
  if (userRole === 'client') return <><OfflineBanner /><ClientDash logout={logout} name={userName} uid={userId} /></>
  if (userRole === 'cleaner') return <><OfflineBanner /><CleanerDash logout={logout} name={userName} uid={userId} /></>
  return null
}

